import{_ as d,o as r,c as a,a5 as o}from"./chunks/framework.D9Kapg2s.js";const g=JSON.parse('{"title":"项目管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/projects.md","filePath":"zh/guide/projects.md"}'),e={name:"zh/guide/projects.md"};function l(i,t,s,n,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="项目管理" tabindex="-1">项目管理 <a class="header-anchor" href="#项目管理" aria-label="Permalink to &quot;项目管理&quot;">​</a></h1><p>项目是组织一次翻译工作的基本单位：语言方向、源文件（资源）、术语表与翻译作业都挂在项目下。</p><p>尚未跑通第一次翻译？请先看 <a href="/zh/guide/getting-started.html">快速开始 · Web</a>。名词解释见 <a href="/zh/guide/concepts.html">核心概念</a>。</p><h2 id="创建项目" tabindex="-1">创建项目 <a class="header-anchor" href="#创建项目" aria-label="Permalink to &quot;创建项目&quot;">​</a></h2><ol><li>打开 <strong>项目</strong> 页，点击 <strong>新建项目</strong></li><li>填写项目信息： <ul><li><strong>项目名称</strong> — 用于标识项目（最多 80 个字符）</li><li><strong>源语言</strong> — 源文件语言，可用 <code>auto</code> 自动识别</li><li><strong>目标语言</strong> — 要译成的语言</li><li><strong>启用术语表</strong> — 是否在翻译时应用术语规则</li></ul></li><li>点击 <strong>创建</strong>，再点进项目卡片进入工作区</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>创建后可随时改名称、语言与术语表开关。本地模式下你就是唯一用户，无需关心组织归属。</p></div><h3 id="支持的语言-节选" tabindex="-1">支持的语言（节选） <a class="header-anchor" href="#支持的语言-节选" aria-label="Permalink to &quot;支持的语言（节选）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>代码</th><th>语言</th></tr></thead><tbody><tr><td><code>auto</code></td><td>自动识别（仅限源语言）</td></tr><tr><td><code>zh-Hans</code></td><td>简体中文</td></tr><tr><td><code>zh-Hant</code></td><td>繁体中文</td></tr><tr><td><code>en-US</code></td><td>英语（美国）</td></tr><tr><td><code>en-GB</code></td><td>英语（英国）</td></tr><tr><td><code>ja</code></td><td>日语</td></tr><tr><td><code>ko</code></td><td>韩语</td></tr><tr><td><code>fr</code></td><td>法语</td></tr><tr><td><code>de</code></td><td>德语</td></tr><tr><td><code>es</code></td><td>西班牙语</td></tr></tbody></table><p>界面中通常提供更完整的语言列表。</p><h3 id="项目归属-服务器模式-·-预览" tabindex="-1">项目归属（服务器模式 · 预览） <a class="header-anchor" href="#项目归属-服务器模式-·-预览" aria-label="Permalink to &quot;项目归属（服务器模式 · 预览）&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">预览</p><p>组织与多用户归属依赖服务器模式，该模式仍在完善。个人本地使用时只需个人项目即可。</p></div><ul><li><strong>个人项目</strong> — 归属当前用户</li><li><strong>组织项目</strong> — 归属组织（需相应权限）</li></ul><h2 id="项目列表" tabindex="-1">项目列表 <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;项目列表&quot;">​</a></h2><p>首页展示所有项目列表，支持以下功能：</p><ul><li><strong>搜索过滤</strong> — 按项目名称或语言代码搜索</li><li><strong>统计面板</strong> — 显示全部项目数和语言方向数</li><li><strong>排序</strong> — 按更新时间降序排列</li><li><strong>快捷操作</strong> — 右键菜单可查看详情、编辑、查看任务、管理术语表或删除项目</li></ul><h2 id="项目工作区" tabindex="-1">项目工作区 <a class="header-anchor" href="#项目工作区" aria-label="Permalink to &quot;项目工作区&quot;">​</a></h2><p>进入项目后，顶部显示项目基本信息（名称、语言方向、更新时间）和统计指标栏：</p><blockquote><p><strong>界面示意（占位）</strong> · 项目工作区<br> 顶部：项目名、语言方向、资源/段落/已译/作业等统计；下方四个标签：<strong>资源 · 段落 · 作业 · 术语表</strong>。<br><em>待补截图：<code>docs/public/images/workspace.png</code></em></p></blockquote><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>资源数</td><td>项目中的文件总数</td></tr><tr><td>段落数</td><td>待翻译的内容段总数</td></tr><tr><td>已翻译</td><td>已完成翻译的段落数</td></tr><tr><td>已审核</td><td>已通过审核的段落数</td></tr><tr><td>运行中作业</td><td>正在执行的翻译作业数</td></tr></tbody></table><p>工作区包含四个标签页：</p><ol><li><strong>资源文件</strong> — 文件管理（详见下方）</li><li><strong>段落编辑</strong> — 翻译内容查看与编辑</li><li><strong>翻译作业</strong> — 翻译作业管理（详见下方）</li><li><strong>术语表</strong> — 项目术语管理</li></ol><h2 id="管理翻译资源" tabindex="-1">管理翻译资源 <a class="header-anchor" href="#管理翻译资源" aria-label="Permalink to &quot;管理翻译资源&quot;">​</a></h2><h3 id="上传文件" tabindex="-1">上传文件 <a class="header-anchor" href="#上传文件" aria-label="Permalink to &quot;上传文件&quot;">​</a></h3><p>支持以下方式上传文件：</p><ul><li><strong>拖拽上传</strong> — 将文件拖拽到上传区域</li><li><strong>点击上传</strong> — 点击上传按钮选择文件</li><li><strong>批量上传</strong> — 一次最多上传 50 个文件</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>上传前会自动进行冲突检测。如果同名文件已存在，可选择替换或增量更新。</p></div><h3 id="支持的文件格式" tabindex="-1">支持的文件格式 <a class="header-anchor" href="#支持的文件格式" aria-label="Permalink to &quot;支持的文件格式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>扩展名</th><th>说明</th></tr></thead><tbody><tr><td>Markdown</td><td><code>.md</code>, <code>.markdown</code>, <code>.mdx</code></td><td>通用文档格式</td></tr><tr><td>HTML</td><td><code>.html</code>, <code>.htm</code></td><td>标记语言文档</td></tr><tr><td>DOCX</td><td><code>.docx</code></td><td>Word 文档</td></tr><tr><td>EPUB</td><td><code>.epub</code></td><td>电子书格式</td></tr><tr><td>SRT</td><td><code>.srt</code></td><td>字幕格式</td></tr><tr><td>VTT</td><td><code>.vtt</code></td><td>Web 字幕格式</td></tr><tr><td>ASS</td><td><code>.ass</code></td><td>高级字幕格式</td></tr><tr><td>纯文本</td><td><code>.txt</code></td><td>纯文本文件</td></tr><tr><td>JSON</td><td><code>.json</code></td><td>JSON 结构化格式</td></tr><tr><td>YAML</td><td><code>.yaml</code>, <code>.yml</code></td><td>YAML 结构化格式</td></tr><tr><td>TOML</td><td><code>.toml</code></td><td>TOML 结构化格式</td></tr></tbody></table><p>详见 <a href="/zh/guide/formats.html">格式支持</a>。</p><h3 id="资源管理" tabindex="-1">资源管理 <a class="header-anchor" href="#资源管理" aria-label="Permalink to &quot;资源管理&quot;">​</a></h3><p>上传后的资源可以进行以下操作：</p><ul><li><strong>查看</strong> — 浏览源文件内容</li><li><strong>翻译</strong> — 启动翻译作业</li><li><strong>替换</strong> — 上传新文件替换已有资源</li><li><strong>增量更新</strong> — 在保留已有翻译的基础上更新源文件</li><li><strong>下载</strong> — 下载原始文件或翻译结果文件</li><li><strong>删除</strong> — 删除资源及其所有段落和翻译</li></ul><h3 id="epub-特殊支持" tabindex="-1">EPUB 特殊支持 <a class="header-anchor" href="#epub-特殊支持" aria-label="Permalink to &quot;EPUB 特殊支持&quot;">​</a></h3><p>EPUB 格式文件具有专用的虚拟目录结构和章节导航，支持按章节选择翻译。</p><h2 id="翻译作业" tabindex="-1">翻译作业 <a class="header-anchor" href="#翻译作业" aria-label="Permalink to &quot;翻译作业&quot;">​</a></h2><h3 id="创建翻译作业" tabindex="-1">创建翻译作业 <a class="header-anchor" href="#创建翻译作业" aria-label="Permalink to &quot;创建翻译作业&quot;">​</a></h3><ol><li>在项目中选择需要翻译的资源（或资源中的特定段落/章节）</li><li>选择翻译执行计划</li><li>配置作业参数： <ul><li><strong>过滤配置</strong> — 控制对已有翻译的处理方式</li><li><strong>自动审核</strong> — 翻译完成后是否自动标记为已审核</li></ul></li><li>点击 <strong>开始翻译</strong></li></ol><h3 id="过滤配置" tabindex="-1">过滤配置 <a class="header-anchor" href="#过滤配置" aria-label="Permalink to &quot;过滤配置&quot;">​</a></h3><p>创建作业时可配置段落过滤，控制哪些段落需要重新翻译：</p><table tabindex="0"><thead><tr><th>过滤选项</th><th>说明</th></tr></thead><tbody><tr><td>跳过已批准</td><td>跳过已审批通过的段落（默认）</td></tr><tr><td>覆盖未批准</td><td>覆盖所有未审批通过的段落</td></tr><tr><td>覆盖全部</td><td>覆盖所有段落，无论状态</td></tr></tbody></table><p>过滤配置可在执行计划中预设默认值，创建作业时按需覆盖。</p><h3 id="作业状态" tabindex="-1">作业状态 <a class="header-anchor" href="#作业状态" aria-label="Permalink to &quot;作业状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>等待中</td><td>作业已创建，等待执行</td></tr><tr><td>运行中</td><td>正在进行翻译</td></tr><tr><td>已完成</td><td>翻译完成</td></tr><tr><td>失败</td><td>翻译失败，可查看错误信息或重试</td></tr><tr><td>已取消</td><td>用户手动取消的作业</td></tr></tbody></table><h3 id="进度追踪" tabindex="-1">进度追踪 <a class="header-anchor" href="#进度追踪" aria-label="Permalink to &quot;进度追踪&quot;">​</a></h3><p>翻译过程中通过 SSE 实时推送进度信息（支持断线重连、事件持久化）：</p><ul><li><strong>翻译进度</strong> — 已完成段数 / 总段数</li><li><strong>预计剩余时间 (ETA)</strong></li><li><strong>当前翻译速度</strong></li><li><strong>事件序号（seq）</strong> — 保证事件顺序，重连后可精准恢复丢失的事件</li></ul><h3 id="作业操作" tabindex="-1">作业操作 <a class="header-anchor" href="#作业操作" aria-label="Permalink to &quot;作业操作&quot;">​</a></h3><ul><li><strong>取消</strong> — 取消正在运行的作业</li><li><strong>重试</strong> — 对失败的作业重新执行翻译</li></ul><h2 id="项目设置" tabindex="-1">项目设置 <a class="header-anchor" href="#项目设置" aria-label="Permalink to &quot;项目设置&quot;">​</a></h2><h3 id="语言设置" tabindex="-1">语言设置 <a class="header-anchor" href="#语言设置" aria-label="Permalink to &quot;语言设置&quot;">​</a></h3><ul><li>修改源语言和目标语言</li><li>切换源语言自动识别</li></ul><h3 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h3><p>将术语表关联到项目，翻译时自动应用术语规则。启用后，翻译引擎会优先使用术语表中的翻译结果。</p><p>详见 <a href="/zh/guide/glossary.html">术语表管理</a>。</p><h2 id="项目删除" tabindex="-1">项目删除 <a class="header-anchor" href="#项目删除" aria-label="Permalink to &quot;项目删除&quot;">​</a></h2><p>删除项目时会<strong>级联删除</strong>以下所有关联数据：</p><ul><li>翻译作业及其关联关系</li><li>资源文件及其段落</li><li>术语表条目</li><li>翻译记忆条目</li><li>同步任务记录</li><li>活动日志和使用记录</li></ul><div class="danger custom-block"><p class="custom-block-title">警告</p><p>项目删除操作不可撤销，请谨慎操作。</p></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>阅读 <a href="/zh/guide/translation-config.html">翻译配置 · 使用</a> 了解如何优化翻译效果</li><li>阅读 <a href="/zh/guide/glossary.html">术语表管理</a> 了解术语管理</li><li>阅读 <a href="/zh/guide/review.html">翻译审校</a> 了解翻译质量控制</li></ul>',60)])])}const b=d(e,[["render",l]]);export{g as __pageData,b as default};
